INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Wall Push-Up', 'strength', ARRAY['chest', 'shoulders', 'triceps'], ARRAY['bodyweight'], 'beginner', 'Stand arm''s length from a wall, hands at chest height | Keep body in a straight line from head to heels | Lower chest toward wall by bending elbows to ~45 degrees | Push back to start without locking elbows');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Incline Push-Up', 'strength', ARRAY['chest', 'core', 'shoulders', 'triceps'], ARRAY['bodyweight'], 'beginner', 'Hands on an elevated surface (bench, box, or wall ledge) | Body forms a straight plank line from head to heels | Lower chest to the edge of the surface | Drive through palms to return; squeeze chest at top');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Knee Push-Up', 'strength', ARRAY['chest', 'core', 'shoulders', 'triceps'], ARRAY['bodyweight'], 'beginner', 'Hands shoulder-width apart on the floor | Knees on ground, ankles crossed, hips straight (no piking) | Lower until chest nearly touches the floor | Exhale and press up, maintaining neutral spine');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Standard Push-Up', 'strength', ARRAY['chest', 'core', 'shoulders', 'triceps'], ARRAY['bodyweight'], 'beginner', 'Hands slightly wider than shoulder-width, fingers spread | Body in rigid plank; glutes and abs braced | Lower until chest is 2-3 inches from ground | Full lockout at top without sagging hips');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Wide Push-Up', 'strength', ARRAY['chest', 'shoulders'], ARRAY['bodyweight'], 'beginner', 'Hands placed well outside shoulder-width | Tuck elbows slightly (not flared at 90 degrees) | Emphasize chest stretch at the bottom | Squeeze chest hard at the top of each rep');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Diamond Push-Up', 'strength', ARRAY['chest', 'shoulders', 'triceps'], ARRAY['bodyweight'], 'intermediate', 'Hands together under chest, index fingers and thumbs touching | Elbows track close to the torso | Lower until chest touches hands | Focus on tricep contraction; don''t flare elbows');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Decline Push-Up', 'strength', ARRAY['chest', 'core', 'shoulders', 'triceps'], ARRAY['bodyweight'], 'intermediate', 'Feet elevated on a bench or box (12-24 inches) | Hands shoulder-width on the floor | Maintain straight body line — don''t let hips sag | Lower head toward ground; press back up fully');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Plyometric Push-Up', 'strength', ARRAY['chest', 'core', 'shoulders', 'triceps'], ARRAY['bodyweight'], 'advanced', 'Lower into a standard push-up | Explode upward hard enough for hands to leave the ground | Land softly with slightly bent elbows to absorb impact | Immediately descend into the next rep');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Archer Push-Up', 'strength', ARRAY['chest', 'core', 'shoulders', 'triceps'], ARRAY['bodyweight'], 'advanced', 'Wide hand placement, one arm straight while other bends | Lower body toward the bending arm''s side | Straight arm acts as a guide — minimal weight on it | Alternate sides each rep or complete all reps on one side first');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Ring or Bench Dip', 'strength', ARRAY['chest', 'shoulders', 'triceps'], ARRAY['bodyweight'], 'beginner', 'Hands on bench behind you, feet flat on floor with knees bent | Lower body by bending elbows to ~90 degrees | Keep back close to the bench — don''t drift forward | Press up and squeeze triceps at the top');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Parallel Bar Dip', 'strength', ARRAY['chest', 'core', 'shoulders', 'triceps'], ARRAY['bodyweight'], 'intermediate', 'Grip bars firmly, arms straight to start | Lean slightly forward to emphasize chest; upright for triceps | Lower until upper arms are parallel to floor | Press up without shrugging shoulders — lock out fully');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Ring Dip', 'strength', ARRAY['chest', 'core', 'shoulders', 'triceps'], ARRAY['bodyweight'], 'advanced', 'Support yourself on rings with arms locked out | Lower slowly — rings will try to drift outward; resist this | Go as deep as shoulder mobility allows | Press up with full control; rings turn out slightly at top');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Pike Push-Up', 'strength', ARRAY['chest', 'core', 'shoulders', 'triceps'], ARRAY['bodyweight'], 'intermediate', 'Start in a push-up position then walk feet toward hands to form an inverted V | Hips high, head looking at feet (not tucking chin) | Lower head toward floor between your hands | Press back up, driving through the shoulders');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Elevated Pike Push-Up', 'strength', ARRAY['chest', 'core', 'shoulders', 'triceps'], ARRAY['bodyweight'], 'intermediate', 'Feet elevated on a box or bench, hips stacked more over shoulders | Create the most vertical torso angle you can manage | Lower crown of head toward floor | Press up explosively; think about pushing the floor away');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Handstand Hold (Wall-Assisted)', 'strength', ARRAY['core', 'forearms', 'shoulders', 'triceps'], ARRAY['bodyweight'], 'intermediate', 'Kick up or wall-walk into a handstand with chest toward wall | Fingers spread wide, grip the floor | Stack shoulders over wrists, hips over shoulders | Hold 20-60 seconds; aim for 30 seconds before progressing');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Handstand Push-Up (Wall-Assisted)', 'strength', ARRAY['back', 'core', 'shoulders', 'triceps'], ARRAY['bodyweight'], 'advanced', 'Kick up to handstand against wall | Lower slowly until head lightly touches floor (use a pad) | Elbows track at ~45 degrees — don''t flare out | Press back to full lockout; maintain hollow body throughout');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Freestanding Handstand Push-Up', 'strength', ARRAY['back', 'core', 'forearms', 'shoulders', 'triceps'], ARRAY['bodyweight'], 'advanced', 'Find balance in a freestanding handstand first | Lower with full control — no rushing | Press back up while maintaining balance | This is a top-tier skill — prioritize form over reps');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dead Hang', 'strength', ARRAY['forearms', 'shoulders'], ARRAY['bodyweight'], 'beginner', 'Hang from a bar with overhand grip, shoulder-width apart | Arms fully extended, shoulders relaxed away from ears | Engage core slightly — don''t be completely limp | Build up to 30-60 second holds');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Scapular Pull-Up', 'strength', ARRAY['back', 'forearms'], ARRAY['bodyweight'], 'beginner', 'Hang from bar with straight arms | Depress and retract shoulder blades (pull shoulders down and back) | Hold the top of the scapular retraction for 1-2 seconds | Release slowly — arms stay straight the entire time');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Negative Pull-Up', 'strength', ARRAY['back', 'biceps', 'forearms'], ARRAY['bodyweight'], 'beginner', 'Jump or step up to chin above bar | Lower as slowly as possible (aim for 3-5 seconds) | Full dead hang at bottom, then jump back up | Focus on eccentric control — this builds strength for full pull-ups');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Band-Assisted Pull-Up', 'strength', ARRAY['back', 'biceps', 'forearms'], ARRAY['bodyweight'], 'beginner', 'Loop a resistance band over the bar and place one foot/knee in it | Pull until chin clears the bar | Control the descent — don''t just drop | Use progressively lighter bands as you get stronger');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Standard Pull-Up (Overhand)', 'strength', ARRAY['back', 'biceps', 'core', 'forearms'], ARRAY['bodyweight'], 'intermediate', 'Grip bar with palms facing away, slightly wider than shoulders | Initiate by depressing scapulae, then pull elbows down to ribs | Chin clears the bar at the top | Lower to full dead hang — no half reps');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Chin-Up (Underhand)', 'strength', ARRAY['back', 'biceps', 'core', 'forearms'], ARRAY['bodyweight'], 'intermediate', 'Grip bar with palms facing you, shoulder-width apart | Pull until chin clears bar; squeeze biceps at top | Lower with control to full extension | Easier than pull-up for most people due to bicep involvement');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Wide-Grip Pull-Up', 'strength', ARRAY['back', 'biceps', 'forearms'], ARRAY['bodyweight'], 'intermediate', 'Grip 1.5x shoulder width or wider | Pull elbows out and down — emphasize lat stretch at bottom | Aim to get chin or chest to bar height | Great for developing V-taper back width');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Commando Pull-Up', 'strength', ARRAY['back', 'biceps', 'core', 'forearms'], ARRAY['bodyweight'], 'advanced', 'Grip bar with one hand in front of the other (mixed grip on same bar) | Pull up, bringing one shoulder to the bar | Alternate which shoulder reaches the bar each rep | Core stays tight to resist twisting');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Archer Pull-Up', 'strength', ARRAY['back', 'biceps', 'chest', 'forearms'], ARRAY['bodyweight'], 'advanced', 'Wide grip, pull toward one hand while the other arm stays straight | Straight arm acts as a guide — minimal load on it | Alternate sides or complete all reps on one side first | Key progression toward one-arm pull-up');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Inverted Row (Australian Pull-Up)', 'strength', ARRAY['back', 'biceps', 'shoulders'], ARRAY['bodyweight'], 'beginner', 'Set bar at waist height; grip bar with overhand grip | Body in straight plank line, heels on floor | Pull chest to bar by retracting shoulder blades | Lower with control; adjust difficulty by changing body angle (more horizontal = harder)');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Elevated Inverted Row', 'strength', ARRAY['back', 'biceps', 'core', 'shoulders'], ARRAY['bodyweight'], 'intermediate', 'Set bar at chest height; feet elevated on a box | Body nearly parallel to the ground | Pull chest firmly to bar; pause at top | Harder than feet-on-floor rows due to increased load');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Tuck Front Lever Row', 'strength', ARRAY['back', 'biceps', 'core', 'shoulders'], ARRAY['bodyweight'], 'advanced', 'Hang from bar, pull into a tuck front lever (knees to chest, body horizontal) | From this position, perform a rowing motion to the bar | Maintain the lever position throughout — don''t drop hips | Advanced body awareness move; master front lever hold first');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Kipping Muscle-Up Transition', 'strength', ARRAY['back', 'biceps', 'chest', 'core', 'triceps'], ARRAY['bodyweight'], 'intermediate', 'Start with a strong kipping swing on the bar | Pull explosively, driving hips to the bar | Lean forward over the bar and transition wrists | Press out at the top — this is the transition phase of a muscle-up');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Ring Muscle-Up', 'strength', ARRAY['back', 'chest', 'core', 'forearms', 'triceps'], ARRAY['bodyweight'], 'advanced', 'Start in a hang, pull aggressively with a false grip | Transition rings to chest height and roll wrists over | Lean forward into the dip portion | Lock out at the top — rings turned out, full support hold');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Bodyweight Squat', 'strength', ARRAY['glutes', 'hamstrings', 'legs'], ARRAY['bodyweight'], 'beginner', 'Feet shoulder-width apart, toes slightly out | Sit hips back and down as if sitting in a chair | Knees track over toes — don''t let them cave inward | Go to at least parallel (thighs parallel to floor); chest up throughout');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Pause Squat', 'strength', ARRAY['core', 'glutes', 'hamstrings', 'legs'], ARRAY['bodyweight'], 'beginner', 'Squat to parallel and hold for 2-3 seconds at the bottom | Maintain tension — don''t relax at the bottom | Drive up explosively from the pause | Eliminates the stretch reflex, building starting strength');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Jump Squat', 'strength', ARRAY['calves', 'glutes', 'hamstrings', 'legs'], ARRAY['bodyweight'], 'intermediate', 'Squat to parallel, then explode upward into a jump | Land softly on the balls of the feet and immediately descend | Keep chest up and knees tracking over toes on landing | Builds power and cardiovascular demand');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Bulgarian Split Squat', 'strength', ARRAY['core', 'glutes', 'hamstrings', 'legs'], ARRAY['bodyweight'], 'intermediate', 'Rear foot elevated on a bench behind you | Lower front thigh to parallel; front shin stays roughly vertical | Keep torso upright; don''t lean excessively forward | Targets each leg independently — great for imbalances');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Walking Lunge', 'strength', ARRAY['core', 'glutes', 'hamstrings', 'legs'], ARRAY['bodyweight'], 'beginner', 'Step forward into a deep lunge, back knee nearly touches floor | Drive through front heel to step the back foot forward into the next lunge | Keep torso upright, core braced | Alternate legs continuously — don''t stop between steps');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Pistol Squat (Assisted)', 'strength', ARRAY['calves', 'core', 'glutes', 'hamstrings', 'legs'], ARRAY['bodyweight'], 'intermediate', 'Hold a doorframe, TRX, or partner''s hand for balance support | Extend one leg forward, squat on the other | Keep heel flat on the floor throughout | Use less assistance as strength and mobility improve');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Pistol Squat', 'strength', ARRAY['calves', 'core', 'glutes', 'hamstrings', 'legs'], ARRAY['bodyweight'], 'advanced', 'Stand on one leg, other leg extended forward | Squat down until hamstring touches calf; extended leg stays off the floor | Drive through the full foot to stand — don''t let heel lift | Requires both strength and ankle/hip mobility');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Nordic Hamstring Curl', 'strength', ARRAY['calves', 'glutes', 'hamstrings'], ARRAY['bodyweight'], 'advanced', 'Kneel with ankles secured under a bar or partner''s hands | Lower torso toward the floor using only hamstrings | Keep hips extended (don''t break at the hips) | Catch yourself with hands at the bottom if needed; push back up');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Front Plank', 'strength', ARRAY['back', 'core', 'shoulders'], ARRAY['bodyweight'], 'beginner', 'Forearms on ground, elbows under shoulders | Body forms a straight line from head to heels | Squeeze glutes, brace abs as if someone might punch your stomach | Don''t let hips sag or pike up — hold 20-60 seconds');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Side Plank', 'strength', ARRAY['core', 'glutes', 'shoulders'], ARRAY['bodyweight'], 'beginner', 'Stack feet or stagger them for balance; forearm on the ground | Lift hips to form a straight line from head to feet | Top arm can rest on hip or extend upward | Hold each side for 20-60 seconds');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Hollow Body Hold', 'strength', ARRAY['core'], ARRAY['bodyweight'], 'intermediate', 'Lie on your back, press lower back firmly into the floor | Lift legs and shoulders off the ground, arms extended overhead | Body forms a shallow banana/crescent shape | Hold 20-60 seconds — lower back must stay flat on floor');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('L-Sit', 'strength', ARRAY['core', 'legs', 'triceps'], ARRAY['bodyweight'], 'intermediate', 'Press hands into floor (or parallel bars) and lock arms straight | Lift body off ground, legs extended straight in front, parallel to floor | Toes pointed, chest up — don''t hunch forward | Hold 10-30 seconds; tuck knees to chest for easier variation');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Hanging Leg Raise', 'strength', ARRAY['core', 'forearms'], ARRAY['bodyweight'], 'intermediate', 'Hang from a bar with overhand grip | Raise legs to at least parallel (90 degrees) using abs, not momentum | Control the descent — no swinging | Progress from knees bent to straight legs as strength increases');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Toes-to-Bar', 'strength', ARRAY['back', 'core', 'forearms'], ARRAY['bodyweight'], 'advanced', 'Hang from bar and raise straight legs until toes touch the bar | Initiate with a slight kip if doing high-rep sets (CrossFit style) | For strict form: no kipping, full control throughout | Full range of motion — legs return to dead hang between reps');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dragon Flag', 'strength', ARRAY['back', 'core', 'glutes'], ARRAY['bodyweight'], 'advanced', 'Lie on a bench, grip the edge behind your head | Raise entire body off the bench — only upper back/shoulders remain in contact | Lower body as a single unit (no breaking at the hips) | Raise back up using core strength — this is a high-level core exercise');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Ab Wheel Rollout', 'strength', ARRAY['back', 'core', 'shoulders'], ARRAY['bodyweight'], 'intermediate', 'Kneel with hands on ab wheel | Roll forward, extending arms while keeping core braced and back neutral | Go as far as you can while maintaining control | Pull back to start using abs — don''t let low back sag');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Back Squat', 'strength', ARRAY['core', 'glutes', 'hamstrings', 'legs'], ARRAY['barbell'], 'intermediate', 'Feet shoulder-width apart, toes slightly out. Unrack bar from upper traps. Brace core, break at hips and knees simultaneously, descend until thighs are at least parallel to floor. Drive through midfoot to stand. Keep chest up and knees tracking over toes throughout.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Bench Press', 'strength', ARRAY['chest', 'shoulders', 'triceps'], ARRAY['barbell'], 'intermediate', 'Grip bar slightly wider than shoulder width. Retract shoulder blades and arch upper back slightly. Lower bar to mid-chest with elbows at roughly 45 degrees. Press bar back up in slight arc to lockout over shoulders. Keep feet flat and hips on bench.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Deadlift', 'strength', ARRAY['back', 'core', 'forearms', 'glutes', 'hamstrings'], ARRAY['barbell'], 'advanced', 'Stand with feet hip-width, bar over midfoot. Hinge at hips, grip bar just outside knees. Flatten back, brace core, drive through heels. Keep bar close to body as you stand tall. Lower by hinging hips back first, then bending knees once bar passes them. Maintain neutral spine throughout.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Overhead Press', 'strength', ARRAY['core', 'shoulders', 'triceps'], ARRAY['barbell'], 'intermediate', 'Grip bar at shoulder width, bar resting on front deltoids. Brace core and squeeze glutes. Press bar straight up, moving your head back to clear the bar path. Lockout with bar directly over midfoot. Lower under control back to starting position. Avoid excessive lean-back.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Bent-Over Row', 'strength', ARRAY['back', 'biceps', 'core', 'forearms'], ARRAY['barbell'], 'intermediate', 'Hinge at hips until torso is roughly 45 degrees to floor. Grip bar slightly wider than shoulder width. Pull bar toward lower ribs, squeezing shoulder blades together at top. Lower under control. Keep back flat and core braced; avoid rounding or excessive momentum.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Front Squat', 'strength', ARRAY['core', 'glutes', 'legs', 'shoulders'], ARRAY['barbell'], 'advanced', 'Rest bar across front deltoids with elbows high (clean grip or crossed arms). Feet shoulder-width apart. Descend by breaking at knees and hips simultaneously, keeping torso very upright. Descend to at least parallel. Drive up through midfoot while keeping elbows raised.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Romanian Deadlift', 'strength', ARRAY['back', 'forearms', 'glutes', 'hamstrings'], ARRAY['barbell'], 'intermediate', 'Stand with feet hip-width, holding bar at hip level with overhand grip. Push hips back while keeping legs mostly straight (slight knee bend). Lower bar along thighs until you feel a deep hamstring stretch, typically mid-shin. Drive hips forward to return to standing. Keep bar close to body.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Hip Thrust', 'strength', ARRAY['core', 'glutes', 'hamstrings'], ARRAY['barbell'], 'intermediate', 'Sit on floor with upper back against a bench. Roll bar over hips with padding. Drive through heels and squeeze glutes to lift hips until body forms a straight line from knees to shoulders. Pause at top with full glute contraction. Lower under control without resting at bottom.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Lunge', 'strength', ARRAY['core', 'glutes', 'hamstrings', 'legs'], ARRAY['barbell'], 'intermediate', 'Bar across upper back. Take a large step forward and lower back knee toward floor until both knees are at roughly 90 degrees. Front knee stays over ankle. Push through front heel to return to standing. Alternate legs or complete all reps on one side first.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Close-Grip Bench Press', 'strength', ARRAY['chest', 'shoulders', 'triceps'], ARRAY['barbell'], 'intermediate', 'Grip bar with hands shoulder-width or slightly narrower. Lower bar to lower chest, keeping elbows tucked close to sides. Press up focusing on tricep engagement. Unlike regular bench press, elbows stay close throughout the movement.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Skull Crushers (Lying Tricep Extension)', 'strength', ARRAY['triceps'], ARRAY['barbell (ez bar preferred)'], 'intermediate', 'Lie on bench, arms extended above chest with slight elbow bend. Lower bar toward forehead by bending only at elbows. Keep upper arms stationary and perpendicular to floor. Extend elbows to return to start. Don''t flare elbows outward.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Curl', 'strength', ARRAY['biceps', 'forearms'], ARRAY['barbell (ez bar optional)'], 'beginner', 'Stand with feet hip-width, grip bar at shoulder width with palms up. Curl bar toward shoulders by flexing elbows, keeping upper arms stationary at sides. Squeeze at top. Lower under control without swinging. Avoid using momentum or arching back.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Pendlay Row', 'strength', ARRAY['back', 'biceps', 'core', 'forearms'], ARRAY['barbell'], 'advanced', 'Hinge to torso parallel with floor. Bar starts on ground each rep. Explosively pull bar to lower chest, then return bar to ground. Each rep starts from a dead stop on the floor. Maintain strict parallel torso position; avoid raising torso during the pull.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Shrugs', 'strength', ARRAY['back', 'forearms'], ARRAY['barbell'], 'beginner', 'Stand upright, grip bar at hip width. Elevate shoulders straight up toward ears as high as possible. Hold at top for a brief squeeze. Lower under control. Avoid rolling shoulders in circles — use a straight up-and-down motion.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Upright Row', 'strength', ARRAY['back', 'biceps', 'shoulders'], ARRAY['barbell'], 'intermediate', 'Grip bar at shoulder width or slightly narrower, arms hanging. Pull bar up along body to upper chest level, leading with elbows. Elbows should end higher than wrists. Lower under control. Use a wider grip or limit range to reduce shoulder impingement risk.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Clean and Press', 'strength', ARRAY['back', 'core', 'glutes', 'hamstrings', 'legs', 'shoulders', 'triceps'], ARRAY['barbell'], 'advanced', 'Start with bar on floor over midfoot. Deadlift with explosive hip extension, then shrug and pull yourself under the bar to catch in front rack position. Stand tall, then press bar overhead to lockout. This is a two-part compound: clean the bar to shoulders, then press overhead.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Floor Press', 'strength', ARRAY['chest', 'shoulders', 'triceps'], ARRAY['barbell'], 'intermediate', 'Lie on floor, grip bar slightly wider than shoulder width. Lower bar until upper arms touch floor, pause briefly, then press back up. Triceps and elbows rest on floor at bottom, reducing range of motion compared to bench press. Focus on lockout strength.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Good Mornings', 'strength', ARRAY['back', 'core', 'glutes', 'hamstrings'], ARRAY['barbell'], 'intermediate', 'Bar across upper back like a squat. Stand with feet hip-width. Hinge at hips, pushing them back while keeping back flat and slight knee bend. Lower torso until it''s nearly parallel with floor or until hamstring flexibility limits you. Return to standing by driving hips forward.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Hack Squat', 'strength', ARRAY['glutes', 'legs'], ARRAY['barbell'], 'advanced', 'Stand on platform, position bar behind legs at calf level. Grip bar behind you with arms extended. Squat down by bending knees and hips, lowering body while bar travels behind legs. Drive up through feet to stand. Emphasizes quads due to the bar position behind the body.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Barbell Sumo Deadlift', 'strength', ARRAY['back', 'core', 'forearms', 'glutes', 'hamstrings', 'legs'], ARRAY['barbell'], 'advanced', 'Stand with feet very wide (1.5x shoulder width), toes pointed out 30-45 degrees. Grip bar between legs with narrow grip. Drive knees out over toes, keep chest up. Push floor apart with feet as you stand. Lockout by squeezing glutes. More quad and glute emphasis than conventional deadlift.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Bench Press', 'strength', ARRAY['chest', 'shoulders', 'triceps'], ARRAY['dumbbells'], 'beginner', 'Lie on bench with dumbbells at chest level, palms facing forward. Press dumbbells up and slightly inward until arms are extended. Lower to chest level with elbows flaring out about 45-75 degrees. Greater range of motion than barbell; allows each arm to work independently.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Shoulder Press', 'strength', ARRAY['core', 'shoulders', 'triceps'], ARRAY['dumbbells'], 'beginner', 'Start with dumbbells at shoulder height, palms facing forward. Press dumbbells overhead until arms are fully extended, dumbbells nearly touching at top. Lower back to shoulders under control. Keep core braced and avoid arching lower back excessively.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Lateral Raise', 'strength', ARRAY['shoulders'], ARRAY['dumbbells'], 'beginner', 'Stand with dumbbells at sides, slight bend in elbows. Raise arms out to sides until parallel with floor, leading with elbows. Pause briefly at top. Lower slowly. Imagine pouring a pitcher of water at the top for slight internal rotation. Keep torso upright, avoid swinging.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Bicep Curl', 'strength', ARRAY['biceps', 'forearms'], ARRAY['dumbbells'], 'beginner', 'Stand with dumbbells at sides, palms facing forward. Curl dumbbells toward shoulders by flexing elbows, keeping upper arms stationary. Rotate wrists (supinate) at top for peak contraction. Lower under control. Avoid swinging or leaning back.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Tricep Kickback', 'strength', ARRAY['triceps'], ARRAY['dumbbells'], 'beginner', 'Hinge at hips with flat back, upper arm parallel to floor and stationary. Extend elbow to straighten arm behind you, squeezing tricep at full extension. Lower back to 90 degrees at elbow. Keep upper arm fixed — only the forearm moves.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Row (Single-Arm)', 'strength', ARRAY['back', 'biceps', 'core', 'forearms'], ARRAY['dumbbells'], 'beginner', 'Place one knee and hand on bench for support, other foot on floor. Row dumbbell toward hip by driving elbow up and back, squeezing shoulder blade at top. Lower under control. Keep hips square and spine neutral; avoid rotating torso.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Goblet Squat', 'strength', ARRAY['core', 'glutes', 'hamstrings', 'legs'], ARRAY['dumbbells'], 'beginner', 'Hold one dumbbell vertically at chest with both hands cupping the top end. Feet shoulder-width apart, toes slightly out. Squat down keeping chest up and elbows inside knees. Descend to at least parallel. Drive through heels to stand. Excellent squat pattern teacher.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Lunges (Walking)', 'strength', ARRAY['core', 'glutes', 'hamstrings', 'legs'], ARRAY['dumbbells'], 'intermediate', 'Hold dumbbells at sides. Step forward into a lunge, lowering back knee toward floor until both knees are at 90 degrees. Push off front foot and step the back foot forward into the next lunge. Alternate legs. Keep torso upright and front knee tracking over toes.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Chest Fly', 'strength', ARRAY['chest', 'shoulders'], ARRAY['dumbbells'], 'intermediate', 'Lie on bench with dumbbells above chest, arms slightly bent. Open arms wide, lowering dumbbells to the sides in a hugging arc until you feel a chest stretch. Bring dumbbells back together over chest, squeezing pecs. Maintain slight elbow bend throughout; don''t lock elbows.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Incline Bench Press', 'strength', ARRAY['chest', 'shoulders', 'triceps'], ARRAY['dumbbells'], 'intermediate', 'Set bench to 30-45 degree incline. Press dumbbells from chest level upward and slightly inward. Incline angle shifts emphasis to upper chest (clavicular head of pec major) and front deltoids. Lower to chest level with controlled tempo.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Romanian Deadlift', 'strength', ARRAY['back', 'forearms', 'glutes', 'hamstrings'], ARRAY['dumbbells'], 'intermediate', 'Stand with dumbbells in front of thighs, palms facing body. Push hips back with slight knee bend, lowering dumbbells along thighs/shins. Hinge until hamstring stretch limit. Return to standing by driving hips forward. Keep dumbbells close to body and back flat.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Renegade Row', 'strength', ARRAY['back', 'biceps', 'core', 'forearms', 'shoulders'], ARRAY['dumbbells'], 'advanced', 'Start in push-up position gripping dumbbells on floor. Row one dumbbell to hip while stabilizing with the other arm and engaging core to resist rotation. Lower and alternate sides. Keep hips level and minimize body rotation throughout.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Arnold Press', 'strength', ARRAY['core', 'shoulders', 'triceps'], ARRAY['dumbbells'], 'intermediate', 'Hold dumbbells at chest level with palms facing you. As you press up, rotate palms to face forward at lockout. Reverse the rotation on the way down. The rotation recruits all three deltoid heads more evenly than a standard press. Keep core braced throughout.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Hammer Curl', 'strength', ARRAY['biceps', 'forearms'], ARRAY['dumbbells'], 'beginner', 'Stand with dumbbells at sides, palms facing each other (neutral grip). Curl toward shoulders keeping palms facing inward throughout. Squeeze at top, lower under control. Targets the brachialis and brachioradialis more than supinated curls.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Front Raise', 'strength', ARRAY['shoulders'], ARRAY['dumbbells'], 'beginner', 'Stand with dumbbells in front of thighs, palms facing down. Raise one or both dumbbells forward to shoulder height with a slight elbow bend. Lower under control. Keep torso stable — avoid swinging or using momentum. Targets anterior deltoids.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Step-Up', 'strength', ARRAY['calves', 'glutes', 'hamstrings', 'legs'], ARRAY['dumbbells'], 'intermediate', 'Hold dumbbells at sides, stand facing a box or bench. Step up with one foot, driving through that heel to stand fully on the box. Step back down with the same leg. Complete all reps on one side before switching. Box height should allow thigh parallel at bottom.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Overhead Tricep Extension', 'strength', ARRAY['triceps'], ARRAY['dumbbells'], 'intermediate', 'Hold one dumbbell with both hands overhead, arms extended. Lower dumbbell behind head by bending elbows, keeping upper arms close to ears. Extend elbows to press dumbbell back overhead. Keep elbows pointing forward and close together — don''t let them flare out.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Bulgarian Split Squat', 'strength', ARRAY['core', 'glutes', 'hamstrings', 'legs'], ARRAY['dumbbells'], 'intermediate', 'Stand lunge distance from a bench, place rear foot on bench behind you. Hold dumbbells at sides. Lower back knee toward floor until front thigh is roughly parallel. Drive through front foot to stand. Keep torso upright and front knee over ankle. Challenges balance and single-leg strength.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Chest-Supported Row', 'strength', ARRAY['back', 'biceps', 'forearms'], ARRAY['dumbbells'], 'intermediate', 'Set bench to 30-45 degrees, lie face down holding dumbbells with arms extended. Row dumbbells toward hips, squeezing shoulder blades together at top. Lower under control. Chest support eliminates momentum and isolates back muscles.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Dumbbell Reverse Fly', 'strength', ARRAY['back', 'shoulders'], ARRAY['dumbbells'], 'intermediate', 'Lie face down on incline bench (or bend over standing) with dumbbells hanging. Raise dumbbells out to sides in an arc, squeezing rear delts and upper back. Lower slowly. Slight bend in elbows, palms facing each other. Targets posterior deltoids and rhomboids.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Running (Outdoor/Treadmill)', 'cardio', ARRAY['calves', 'core', 'glutes', 'hamstrings', 'legs'], ARRAY['none (treadmill optional)'], 'beginner', 'Land midfoot with slight forward lean from ankles. Maintain a cadence of ~170-180 steps per minute. Arms swing forward and back (not across body). Keep shoulders relaxed and gaze forward. Start with walk/jog intervals if new to running.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Cycling (Stationary Bike)', 'cardio', ARRAY['calves', 'glutes', 'hamstrings', 'legs'], ARRAY['cardio_machine'], 'beginner', 'Set seat height so knee has slight bend at bottom of pedal stroke. Maintain consistent cadence (70-90 RPM for steady state). Keep back neutral, grip handlebars lightly. For intervals, alternate resistance or speed. Low-impact option good for joint health.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Rowing Machine (Ergometer)', 'cardio', ARRAY['back', 'biceps', 'core', 'glutes', 'hamstrings', 'legs', 'shoulders'], ARRAY['cardio_machine'], 'intermediate', 'Drive sequence: legs first, then lean back, then pull handle to lower ribs. Recovery reverses: arms away, lean forward, bend knees. Ratio should be 1:2 (drive:recovery). Keep core braced, back straight. Power comes from legs (~60%), not arms.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Jump Rope', 'cardio', ARRAY['calves', 'core', 'forearms', 'shoulders'], ARRAY['jump_rope'], 'intermediate', 'Jump only 1-2 inches off ground, landing softly on balls of feet. Wrists rotate the rope — not arms. Keep elbows close to ribs. Breathe rhythmically. Maintain upright posture with gaze forward. Start with 30-second intervals and build duration.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Burpees', 'cardio', ARRAY['chest', 'core', 'glutes', 'legs', 'shoulders'], ARRAY['bodyweight'], 'intermediate', 'From standing, squat down and place hands on floor. Jump feet back to push-up position. Perform push-up (optional). Jump feet to hands. Explode upward into a jump with arms overhead. Move continuously through all phases. Scale by stepping instead of jumping.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Mountain Climbers', 'cardio', ARRAY['core', 'legs', 'shoulders'], ARRAY['bodyweight'], 'beginner', 'Start in push-up/plank position. Drive one knee toward chest, then quickly switch legs in a running motion. Keep hips level (don''t pike up). Maintain a flat back and engaged core. Speed can be varied from slow and controlled to fast and explosive.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Battle Rope Waves', 'cardio', ARRAY['core', 'forearms', 'shoulders'], ARRAY['battle_ropes'], 'intermediate', 'Stand with athletic stance, grip rope in each hand. Alternate arms to create alternating waves, or move both arms simultaneously for double waves. Keep core braced and sink into a slight squat. Maintain consistent wave height and rhythm. Great for conditioning.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Kettlebell Swing', 'cardio', ARRAY['core', 'glutes', 'hamstrings', 'shoulders'], ARRAY['kettlebell'], 'intermediate', 'Stand with feet slightly wider than shoulder width, kettlebell in front. Hike kettlebell back between legs, then snap hips forward explosively to swing it to chest/eye level. Arms are hooks — the power comes from hip hinge. Squeeze glutes at top. Don''t squat the weight.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Stair Climber / Stair Running', 'cardio', ARRAY['calves', 'glutes', 'hamstrings', 'legs'], ARRAY['cardio_machine'], 'beginner', 'Place full foot on each step. Drive through heel to step up, engaging glutes. Maintain upright posture with hands lightly on rails (don''t lean on them). Keep a consistent pace. Simulate a brisk walking pace for steady-state; run stairs for high-intensity intervals.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Swimming (Freestyle/Front Crawl)', 'cardio', ARRAY['back', 'chest', 'core', 'legs', 'shoulders'], ARRAY['pool'], 'intermediate', 'Body horizontal with face in water. Alternate arm strokes pulling water past hips while head rotates to breathe. Kick with flutter kick from hips (not knees). Maintain streamlined body position. Breathe every 2-3 strokes. Excellent full-body, zero-impact conditioning.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Box Jumps', 'cardio', ARRAY['calves', 'core', 'glutes', 'hamstrings', 'legs'], ARRAY['plyo_box'], 'intermediate', 'Stand facing box at comfortable distance. Swing arms back and bend knees, then explode upward, landing softly on box with both feet. Stand fully upright on box. Step or jump back down one foot at a time. Start with a low box and progress height as power improves.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Assault Bike / Air Bike', 'cardio', ARRAY['core', 'glutes', 'hamstrings', 'legs', 'shoulders'], ARRAY['cardio_machine'], 'intermediate', 'Pedal and push/pull handles simultaneously. Resistance increases with effort — the harder you go, the more resistance. Use for steady-state endurance or sprint intervals (e.g., 20 seconds all-out, 40 seconds rest). Keep core engaged throughout.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('High Knees', 'cardio', ARRAY['calves', 'core', 'legs'], ARRAY['bodyweight'], 'beginner', 'Run in place, driving knees up to hip height or higher with each step. Land on balls of feet with quick turnover. Pump arms in rhythm. Keep torso upright with engaged core. Can be done as warm-up or high-intensity interval.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Ski Erg', 'cardio', ARRAY['back', 'core', 'forearms', 'shoulders'], ARRAY['cardio_machine'], 'intermediate', 'Grip handles overhead with arms extended. Pull handles down past hips by hinging at hips and engaging lats and core. Return arms overhead by hinging back up. Mimics Nordic skiing motion. Focus on core engagement and hip hinge for power generation.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Sprints (Track/Field)', 'cardio', ARRAY['calves', 'core', 'glutes', 'hamstrings', 'legs'], ARRAY['bodyweight'], 'intermediate', 'Run at maximum effort for a short distance (50-400m). Drive arms hard, maintain upright torso with slight forward lean. Push off explosively from ground. Sprint intervals: 10-30 seconds all-out, 1-3 minutes walking recovery. Great for power, speed, and anaerobic capacity.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Cat-Cow Stretch', 'flexibility', ARRAY['back', 'core'], ARRAY['none'], 'beginner', 'Start on hands and knees with wrists under shoulders, knees under hips. Exhale and round spine toward ceiling (cat), tucking chin and tailbone. Inhale and arch spine toward floor (cow), lifting chest and tailbone. Flow smoothly between positions. Great for spinal mobility warm-up.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Downward Dog', 'flexibility', ARRAY['back', 'calves', 'hamstrings', 'shoulders'], ARRAY['none'], 'beginner', 'From hands and knees, lift hips up and back to form an inverted V shape. Press hands firmly into floor, push chest toward thighs. Straighten legs as much as hamstring flexibility allows — keep a slight bend if needed. Push heels toward floor. Breathe deeply for 5-10 breaths.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Hip Flexor Stretch (Half-Kneeling)', 'flexibility', ARRAY['core', 'glutes', 'legs'], ARRAY['none'], 'beginner', 'Kneel with one knee on mat, other foot forward with knee at 90 degrees. Shift hips forward gently until you feel a stretch in the front of the back leg''s hip. Keep torso upright, squeeze glute of back leg. Hold 30-60 seconds each side. Avoid arching lower back.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Standing Hamstring Stretch', 'flexibility', ARRAY['calves', 'hamstrings'], ARRAY['bodyweight'], 'beginner', 'Place one heel on a low surface (step or bench). Keep that leg straight and hinge at hips, reaching toward toes. Keep back flat — don''t round. You should feel the stretch in the back of the raised leg. Hold 30-60 seconds each side. Don''t bounce.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Pigeon Pose', 'flexibility', ARRAY['core', 'glutes'], ARRAY['none'], 'intermediate', 'From downward dog, bring one knee forward behind the wrist, shin angled across body. Extend the other leg straight back. Square hips toward floor and fold forward over front leg if possible. Targets deep external hip rotators (piriformis). Hold 1-2 minutes each side.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Foam Rolling (IT Band)', 'flexibility', ARRAY['glutes', 'legs'], ARRAY['foam_roller'], 'beginner', 'Lie on side with foam roller under outer thigh. Roll slowly from hip to just above knee, pausing on tender spots for 20-30 seconds. Support weight with arms and opposite leg. Moderate pressure — uncomfortable but not painful. Do 1-2 minutes each side before or after workouts.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Thoracic Spine Rotation (Open Book)', 'flexibility', ARRAY['back', 'chest', 'core', 'shoulders'], ARRAY['none'], 'beginner', 'Lie on side with knees stacked at 90 degrees, arms extended in front. Keep knees together and rotate top arm open like a book, following hand with your eyes. Reach as far as possible, feeling a stretch across chest and spine. Hold 5-10 seconds, return. 8-10 reps each side.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Child''s Pose', 'flexibility', ARRAY['back', 'core', 'shoulders'], ARRAY['none'], 'beginner', 'Kneel with knees wide, sit hips back toward heels. Extend arms forward on floor and let chest drop between thighs. Forehead rests on floor. Breathe deeply, feeling a stretch through the back, shoulders, and hips. Hold 30-60 seconds. Excellent relaxation and recovery pose.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Butterfly Stretch', 'flexibility', ARRAY['core', 'glutes', 'legs'], ARRAY['none'], 'beginner', 'Sit with soles of feet together, knees out to sides. Hold feet or ankles. Sit tall and gently press knees toward floor using elbows or gravity. Keep spine straight — don''t round forward. Hold 30-60 seconds. Targets inner thighs (adductors) and hip flexors.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Doorway Chest Stretch', 'flexibility', ARRAY['chest', 'shoulders'], ARRAY['none'], 'beginner', 'Stand in a doorway, place forearms on each side of frame with elbows at shoulder height. Step one foot forward gently until you feel a stretch across your chest. Keep torso upright. Hold 30-60 seconds. Essential for those with tight chest from bench pressing or desk work.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('World''s Greatest Stretch', 'flexibility', ARRAY['back', 'chest', 'core', 'hamstrings', 'shoulders'], ARRAY['bodyweight'], 'intermediate', 'Step into a deep lunge with right foot forward. Place left hand on floor inside right foot. Rotate torso right, reaching right arm toward ceiling. Hold 5 seconds. Return hand to floor, then shift back to straighten front leg (hamstring stretch). Hold 5 seconds. 4-5 reps each side. Combines multiple stretches in one flow.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('90/90 Hip Stretch', 'flexibility', ARRAY['core', 'glutes'], ARRAY['none'], 'intermediate', 'Sit on floor with front leg bent at 90 degrees in front of you, back leg bent at 90 degrees behind you. Sit tall and lean slightly forward over front leg. You should feel a stretch in the front leg''s glute/hip external rotators. Switch sides. Improves hip internal and external rotation.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Supine Spinal Twist', 'flexibility', ARRAY['back', 'chest', 'core', 'glutes'], ARRAY['none'], 'beginner', 'Lie on back, extend arms to T position. Bring one knee to chest, then guide it across body to the opposite side with opposite hand. Keep both shoulders on floor. Look toward the extended arm on the opposite side. Hold 30-60 seconds each side. Gentle spinal rotation and lower back release.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Calf Stretch (Wall/Step)', 'flexibility', ARRAY['calves'], ARRAY['none'], 'beginner', 'Stand facing wall with one foot back, heel on floor. Bend front knee and lean into wall until you feel a stretch in back leg''s calf. For deeper stretch (gastrocnemius), keep back knee straight. For soleus, bend back knee slightly. Hold 30-60 seconds each side.');
INSERT INTO exercises (name, category, muscle_groups, equipment, difficulty, instructions) VALUES ('Couch Stretch', 'flexibility', ARRAY['core', 'glutes', 'legs'], ARRAY['none'], 'intermediate', 'Kneel facing away from a wall or couch. Place rear foot up on wall behind you, knee on floor (or pad). Drive hips forward and squeeze glute of the back leg to intensify the stretch through the quad and hip flexor. Keep torso upright. Hold 30-60 seconds each side. Very effective for tight hip flexors.');
